+// Feature Request methods
+
+func (s *SQLiteStore) CreateFeatureRequest(request *models.FeatureRequest) error {
+	if request.ID == uuid.Nil {
+		request.ID = uuid.New()
+	}
+	request.CreatedAt = time.Now()
