+		request.GitHubIssueNumber, nullString(request.GitHubIssueURL), string(request.Status),
+		request.PRNumber, nullString(request.PRURL), nullString(request.NetlifyPreviewURL),
+		request.UpdatedAt, request.ID.String())
+	return err
+}
